        subtotalCents: 5000,
        discountCents: 0,
        totalCents: 5000,
      });
    });
  });

  describe("result shape and invariants", () => {
    it("returns exactly the three documented keys", () => {
      expect(Object.keys(priceOrder([{ unitCents: 20000, qty: 1 }], { pct: 10 })).sort()).toEqual([
        "discountCents",
        "subtotalCents",
        "totalCents",
      ]);
    });

    it("keeps total = subtotal - discount across a realistic order", () => {
      const result = priceOrder(
        [
          { unitCents: 1299, qty: 3 }, // 3897
          { unitCents: 4999, qty: 2 }, // 9998
          { unitCents: 250, qty: 5 }, //  1250
        ],
        { pct: 20 },
      );
      // subtotal = 15145 -> tier round(1514.5)=1515 -> base 13630
      // coupon 20% of 13630 = 2726 -> discount 4241
      expect(result).toEqual({
        subtotalCents: 15145,
        discountCents: 4241,
        totalCents: 10904,
      });
      expect(result.totalCents).toBe(
        result.subtotalCents - result.discountCents,
      );
    });
  });
});
